diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..e12940d73 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -574,11 +574,17 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 		fontdesc->font = fz_new_font_from_buffer(ctx, fontname, buf, 0, 1);
 	}
 	fz_always(ctx)
-		fz_drop_buffer(ctx, buf);
+	{
+		if (buf != cff)  // Only drop buf if it's not already the CFF buffer (which would have been dropped)
+			fz_drop_buffer(ctx, buf);
+	}
 	fz_catch(ctx)
 		fz_rethrow(ctx);

+	// Use the original stream buffer for size calculation since buf might have been dropped
+	buf = pdf_load_stream(ctx, stmref);  // Reload the stream for size calculation
 	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
+	fz_drop_buffer(ctx, buf);
 	fontdesc->is_embedded = 1;
 }

